import React from "react";
import Navbar from "../components/Navbar";
import styled from "styled-components";
import {Link} from "react-router-dom";

const Container = styled.div`
    width: 100%;
    height: 92vh;
    background-color: #071330;
`;

const Wrapper = styled.div`
    height: 100%;
    display: flex;
    width: 100%;
`;

const InfoContainer = styled.div`
    width: 40%;
    margin-left: 5vw;
    height: 25%;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
`;

const ProjectContainer = styled.div`
    width: 40%;
    margin-left: 5vw;
    display: flex;
    flex-direction: column;
`;

const Info = styled.h2`
    color: white;
`;

const Project = styled.button`
    color: #7BC2BC;
    height: 5vh;
`;
const Home = () => {
    return (
        <div>
            <Navbar/>
            <Container>
                <Wrapper>
                    <InfoContainer>
                        <Info>Hello, I'm <span style={{color: '#7BC2BC'}}> Joel Harawa</span>, a senior at New York University, passionately immersed in the world of Computer Science.</Info>
                        <Info>I'm an aspiring Software engineer, with interests in both front-end and back-end engineering.</Info>
                    </InfoContainer>
                    <ProjectContainer>
                        <Info><span style={{color: '#7BC2BC'}}>Projects</span></Info>
                        <Project>CULTR Magazine</Project>
                        <Project>Moosic</Project>
                        <Project>27 - Puzzle</Project>
                        <Project>E20 Processor</Project>
                        <Project>Piper</Project>
                        <Project>FlyGenie</Project>
                    </ProjectContainer>
                </Wrapper>
            </Container>
        </div>
    );
}

export default Home;
